# ==================================================================
#   EMBEDDED IMAGES (base64)  -- file is fully self-contained
# ==================================================================
BG_B64 = ""
LOGO_B64 = ""
BG_DARK_B64 = ""   # dark-mode full-window background (JPEG, navy robotic-arm scene)
HAND_LIGHT_B64 = ""   # light-mode silver robotic-arm cutout (PNG, alpha)


# ==================================================================
#   THEME
# ==================================================================
# The module-level constants hold the *dark* palette and are used at
# build time by every widget.  Switching to light mode is handled at
# runtime by _apply_theme(), which (a) re-runs the ttk style builder
# using the active palette and (b) walks every tk widget swapping the
# neutral colours below via NEUTRAL_MAP.  Accent colours (header blue,
# highlight red, button colours) are shared by both themes so buttons
# and branding stay legible on either background.
BG_DARK    = "#1a1a2e"   # very dark navy - main background
BG_PANEL   = "#16213e"   # panel background
ACCENT     = "#0f3460"   # accent / header  (shared by both themes)
HIGHLIGHT  = "#e94560"   # red highlight    (shared)
BLUE_BTN   = "#2d6cdf"   # calibration buttons (shared)
GREY_BTN   = "#444a5a"   # (shared)
GREEN      = "#2ecc71"   # (shared)
RED        = "#e74c3c"   # (shared)
AMBER      = "#f39c12"   # (shared)
TEXT       = "#f5f6fa"   # primary text
TEXT_DIM   = "#a4b0be"   # dimmed text
TREE_BG    = "#0e1526"   # treeview / text widget background

# Neutral colours that differ between the two themes.  Keys are the
# dark-palette hex values (as written in the widget builders); values
# are the matching light-palette hex values.  Distinct on both sides so
# the swap is unambiguous and reversible.
NEUTRAL_MAP = {
    BG_DARK:  "#e8edf5",   # main background
    BG_PANEL: "#f7f9fc",   # panels / cards
    TEXT:     "#15223d",   # primary text
    TEXT_DIM: "#5b6b86",   # dimmed text
    TREE_BG:  "#eef3fa",   # treeview / text widgets
}

# Active-palette dictionaries consumed by _build_style().
THEMES = {
    "dark": {
        "bg_dark": BG_DARK, "bg_panel": BG_PANEL, "accent": ACCENT,
        "highlight": HIGHLIGHT, "text": TEXT, "text_dim": TEXT_DIM,
        "tree_bg": TREE_BG,
    },
    "light": {
        "bg_dark": NEUTRAL_MAP[BG_DARK], "bg_panel": NEUTRAL_MAP[BG_PANEL],
        "accent": ACCENT, "highlight": HIGHLIGHT,
        "text": NEUTRAL_MAP[TEXT], "text_dim": NEUTRAL_MAP[TEXT_DIM],
        "tree_bg": NEUTRAL_MAP[TREE_BG],
    },
}

# Where the light/dark preference is remembered between runs.
import os as _os
SETTINGS_PATH = _os.path.join(_os.path.expanduser("~"), ".stork_cal_settings.json")


# ==================================================================
#   MODBUS COMPATIBILITY WRAPPER
#   pymodbus <=3.6 uses slave=, >=3.7 uses device_id=
# ==================================================================
def _unit_kwarg(func):
    try:
        params = inspect.signature(func).parameters
    except (TypeError, ValueError):
        return "slave"
    if "device_id" in params:
        return "device_id"
    return "slave"


class ModbusLink:
    """Thin, thread-safe wrapper around a ModbusSerialClient."""

    def __init__(self):
        self.client = None
        self._tcp_sock = None
        self.address = 2
        self.lock = threading.Lock()
        self._read_kw = "slave"
        self._write_kw = "slave"
        self.mode = "serial"   # "serial" or "tcp"

    @property
    def connected(self):
        if self.mode == "tcp":
            return self._tcp_sock is not None
        return self.client is not None and getattr(self.client, "connected", False)

    def connect(self, port, baud, address, timeout=1):
        """Connect over serial (USB / RS485 RTU)."""
        self.disconnect()
        if not _PYMODBUS_OK:
            raise RuntimeError("pymodbus not installed - run: pip install pymodbus")
        self.mode = "serial"
        self.client = ModbusSerialClient(
            port=port, baudrate=int(baud), bytesize=8,
            parity="N", stopbits=1, timeout=timeout,
        )
        self._read_kw = _unit_kwarg(self.client.read_holding_registers)
        self._write_kw = _unit_kwarg(self.client.write_register)
        self.address = int(address)
        ok = self.client.connect()
        if not ok:
            self.client = None
        return ok

    def connect_tcp(self, host, port, address, framer="socket", timeout=5):
        """Connect to sensor WiFi ASCII gateway on port 8888.

        Opens a raw TCP socket to port 8888 (firmware ASCII command interface).
        Reads use RX260/RX208 ASCII commands — proven reliable.
        Modbus/TCP on port 8502 was unreliable and dropped in firmware V2.0.
        Calibration writes still require a Serial connection.
        """
        self.disconnect()
        import socket as _socket
        self.mode = "tcp"
        self.address = int(address)
        ascii_port = 8888  # Always use the ASCII command port
        try:
            sock = _socket.socket(_socket.AF_INET, _socket.SOCK_STREAM)
            sock.settimeout(timeout)
            sock.connect((host, ascii_port))
            sock.settimeout(4)  # Per-command read timeout
            self._tcp_sock = sock
            print(f"[TCP-ASCII] Connected to {host}:{ascii_port}, address {address}")
            return True
        except Exception as e:
            print(f"[TCP-ASCII] Failed to connect to {host}:{ascii_port}: {e}")
            self._tcp_sock = None
            return False

    def disconnect(self):
        if self._tcp_sock is not None:
            try:
                self._tcp_sock.close()
            except Exception:
                pass
            self._tcp_sock = None
        if self.client is not None:
            try:
                self.client.close()
            except Exception:
                pass
        self.client = None

    def _ascii_cmd(self, cmd, timeout=4):
        """Send one ASCII command to port-8888 and return the stripped response line.
        Returns None on error or disconnect."""
        if self._tcp_sock is None:
            return None
        try:
            self._tcp_sock.settimeout(timeout)
            self._tcp_sock.sendall((cmd + "\n").encode())
            buf = b""
            while b"\n" not in buf:
                chunk = self._tcp_sock.recv(1024)
                if not chunk:
                    break
                buf += chunk
            line = buf.split(b"\n")[0].decode(errors="replace").strip()
            return line if line else None
        except Exception as e:
            print(f"[TCP-ASCII] {cmd!r} error: {e}")
            try:
                self._tcp_sock.close()
            except Exception:
                pass
            self._tcp_sock = None  # auto-disconnect on error
            return None

    # -- low level -------------------------------------------------
    def read(self, reg, count=1, address=None):
        """Read holding register(s). Returns list of raw ints or None on error."""
        if self.mode == "tcp":
            # TCP reads go through _ascii_cmd() / _tds_read_tcp(); not via Modbus
            print(f"[Modbus] read(reg={reg}) skipped — TCP mode uses ASCII commands")
            return None
        if self.client is None:
            print(f"[Modbus] Read failed: client is None")
            return None
        addr = self.address if address is None else int(address)
        kw = {self._read_kw: addr, "count": count}
        try:
            rr = self.client.read_holding_registers(reg, **kw)
        except TypeError:
            # older signature: count positional
            try:
                rr = self.client.read_holding_registers(reg, count, **{self._read_kw: addr})
            except Exception as e:
                print(f"[Modbus] Read exception (reg={reg}, count={count}, addr={addr}): {e}")
                return None
        except Exception as e:
            print(f"[Modbus] Read exception (reg={reg}, count={count}, addr={addr}): {e}")
            return None
        if rr is None or (hasattr(rr, "isError") and rr.isError()):
            err = str(rr) if rr else "No response"
            print(f"[Modbus] Read error (reg={reg}, count={count}, addr={addr}): {err}")
            return None
        return list(rr.registers)

    def write(self, reg, value, address=None):
        """Write single holding register. Returns True/False."""
        if self.mode == "tcp":
            print(f"[TCP] Write blocked (reg={reg}) — calibration requires Serial connection")
            return False
        if self.client is None:
            return False
        addr = self.address if address is None else int(address)
        kw = {self._write_kw: addr}
        try:
            wr = self.client.write_register(reg, int(value), **kw)
        except Exception:
            return False
        if wr is None or (hasattr(wr, "isError") and wr.isError()):
            return False
        return True


def to_signed16(raw):
    return raw - 65536 if raw > 32767 else raw


# ==================================================================
#   MAIN APPLICATION
# ==================================================================
class StorkCalibrationTool:

    def __init__(self, root):
        self.root = root
        self.link = ModbusLink()

        self._bg_photo = None
        self._logo_photo = None
        self._watermark_photo = None
        self._watermark_id = None

        # theme state (light / dark) -- persisted between runs.
        # The whole UI is always *built* with the dark palette (the module
        # constants the widget builders reference); if the saved preference
        # is light we flip everything at the end of __init__ via _apply_theme.
        self._target_theme = self._load_settings().get("theme", "dark")
        if self._target_theme not in THEMES:
            self._target_theme = "dark"
        self.theme = "dark"
        self.C = THEMES["dark"]
        self._page_bg_labels = {}      # key -> background image Label
        self._root_bg_id = None
        self.theme_var = None          # created lazily by the settings popup
        self._settings_win = None

        # polling state
        self.ph_polling = False
        self.tds_polling = False
        self._ph_thread = None
        self._tds_thread = None

        # data logs (list of tuples)
        self.ph_log = []
        self.tds_log = []

        # latest readings cache
        self.ph_latest = {}
        self.tds_latest = {}

        self._build_window()
        self._build_style()
        self._build_background()
        self._build_header()
        self._build_connection_panel()
        self._build_tabs()
        self._refresh_ports()
        self._set_connected_ui(False)

        self.root.protocol("WM_DELETE_WINDOW", self._on_close)

        # apply the persisted preference (flip to light if that was saved)
        self.root.update_idletasks()
        if self._target_theme == "light":
            self._apply_theme("light")
        else:
            self._refresh_backgrounds()

    # -------------------------------------------------- window / style
    def _build_window(self):
        self.root.title("Stork Solutions Ltd Aquatics Calibration Suite")
        self.W, self.H = 1100, 780
        self.root.geometry(f"{self.W}x{self.H}")
        self.root.minsize(1080, 740)
        self.root.configure(bg=BG_DARK)

    def _build_style(self):
        """(Re)build all ttk styles from the active palette (self.C).

        Called once at start-up (dark palette) and again whenever the theme
        is switched, so every ttk widget re-colours to match.
        """
        C = self.C
        bg_dark = C["bg_dark"]
        bg_panel = C["bg_panel"]
        text = C["text"]
        text_dim = C["text_dim"]
        accent = C["accent"]
        highlight = C["highlight"]
        tree_bg = C["tree_bg"]

        st = ttk.Style()
        try:
            st.theme_use("clam")
        except Exception:
            pass
        st.configure(".", background=bg_dark, foreground=text,
                     fieldbackground=bg_panel, bordercolor=accent)
        st.configure("TFrame", background=bg_dark)
        st.configure("Panel.TFrame", background=bg_panel)
        st.configure("TLabel", background=bg_dark, foreground=text)
        st.configure("Dim.TLabel", background=bg_dark, foreground=text_dim)
        st.configure("Panel.TLabel", background=bg_panel, foreground=text)
        st.configure("PanelDim.TLabel", background=bg_panel, foreground=text_dim)
        st.configure("TLabelframe", background=bg_panel, foreground=highlight,
                     bordercolor=accent, relief="groove")
        st.configure("TLabelframe.Label", background=bg_panel,
                     foreground=highlight, font=("Segoe UI", 10, "bold"))
        st.configure("TCheckbutton", background=bg_panel, foreground=text)
        st.map("TCheckbutton", background=[("active", bg_panel)],
               foreground=[("active", text)])
        st.configure("TRadiobutton", background=bg_panel, foreground=text)
        st.map("TRadiobutton", background=[("active", bg_panel)],
               foreground=[("active", text)])
        # input fields stay white with black text in both themes (max legibility)
        st.configure("TCombobox", fieldbackground="#ffffff", foreground="#000000")
        st.configure("TSpinbox", fieldbackground="#ffffff", foreground="#000000",
                     arrowsize=13)
        st.configure("TEntry", fieldbackground="#ffffff", foreground="#000000")

        # notebook (tabs)
        st.configure("TNotebook", background=bg_dark, bordercolor=accent)
        st.configure("TNotebook.Tab", background=accent, foreground=text_dim,
                     padding=(24, 10), font=("Segoe UI", 11, "bold"))
        st.map("TNotebook.Tab",
               background=[("selected", highlight)],
               foreground=[("selected", "#ffffff")])

        # treeview
        st.configure("Treeview", background=tree_bg, fieldbackground=tree_bg,
                     foreground=text, rowheight=22, bordercolor=accent)
        st.configure("Treeview.Heading", background=accent, foreground=text,
                     font=("Segoe UI", 9, "bold"))
        st.map("Treeview", background=[("selected", highlight)])

    # -------------------------------------------------- background images
    def _cover_fit(self, img, w, h):
        """Scale + centre-crop *img* so it completely covers (w, h)."""
        iw, ih = img.size
        if iw == 0 or ih == 0:
            return img
        scale = max(w / iw, h / ih)
        nw, nh = max(1, int(iw * scale)), max(1, int(ih * scale))
        img = img.resize((nw, nh), Image.LANCZOS)
        left = (nw - w) // 2
        top = (nh - h) // 2
        return img.crop((left, top, left + w, top + h))

    def _render_bg_image(self, w, h):
        """Return an ImageTk.PhotoImage of the themed background at (w, h).

        Dark theme  -> the navy robotic-arm photo, cover-fit + gently darkened.
        Light theme -> a soft light wash with the silver robotic-arm cut-out
                       floated bottom-right (semi-transparent) to echo the
                       original v1.0.0 look.
        """
        if not _PIL_OK or w < 2 or h < 2:
            return None
        try:
            if self.theme == "dark":
                raw = base64.b64decode(BG_DARK_B64)
                base = Image.open(io.BytesIO(raw)).convert("RGB")
                base = self._cover_fit(base, w, h).convert("RGBA")
                # slight darken for text contrast
                overlay = Image.new("RGBA", (w, h), (10, 14, 30, 35))
                base = Image.alpha_composite(base, overlay)
            else:
                # light gradient-ish wash (vertical) between two light tones
                top_c = (240, 244, 250)
                bot_c = (220, 229, 242)
                base = Image.new("RGB", (w, h))
                px = base.load()
                for y in range(h):
                    t = y / max(1, h - 1)
                    r = int(top_c[0] + (bot_c[0] - top_c[0]) * t)
                    g = int(top_c[1] + (bot_c[1] - top_c[1]) * t)
                    b = int(top_c[2] + (bot_c[2] - top_c[2]) * t)
                    for x in range(w):
                        px[x, y] = (r, g, b)
                base = base.convert("RGBA")
                # float the silver hand bottom-right, semi-transparent
                raw = base64.b64decode(HAND_LIGHT_B64)
                hand = Image.open(io.BytesIO(raw)).convert("RGBA")
                hw = max(1, int(min(w * 0.70, hand.width)))
                hh = max(1, int(hand.height * (hw / hand.width)))
                hand = hand.resize((hw, hh), Image.LANCZOS)
                alpha = hand.split()[3].point(lambda p: int(p * 0.75))
                hand.putalpha(alpha)
                base.paste(hand, (w - hw - 12, h - hh - 12), hand)
            return ImageTk.PhotoImage(base)
        except Exception as exc:
            print(f"[BG] render failed: {exc}")
            return None

    def _build_background(self):
        """Root-level canvas that fills the whole window with the themed image."""
        self.bg_canvas = tk.Canvas(self.root, highlightthickness=0, bd=0,
                                   bg=self.C["bg_dark"])
        self.bg_canvas.place(x=0, y=0, relwidth=1, relheight=1)
        tk.Misc.lower(self.bg_canvas)   # Canvas.lower() means tag_lower
        self.bg_canvas.bind("<Configure>", self._on_root_bg_configure)

    def _on_root_bg_configure(self, event):
        self._render_root_bg(event.width, event.height)

    def _render_root_bg(self, w=None, h=None):
        if not hasattr(self, "bg_canvas"):
            return
        if w is None:
            w = self.bg_canvas.winfo_width()
        if h is None:
            h = self.bg_canvas.winfo_height()
        photo = self._render_bg_image(w, h)
        if photo is None:
            self.bg_canvas.configure(bg=self.C["bg_dark"])
            return
        self._bg_photo = photo   # keep ref
        if self._root_bg_id is None:
            self._root_bg_id = self.bg_canvas.create_image(0, 0, anchor="nw",
                                                           image=photo)
        else:
            self.bg_canvas.itemconfig(self._root_bg_id, image=photo)
            self.bg_canvas.coords(self._root_bg_id, 0, 0)

    def _install_page_bg(self, parent, key):
        """Put a themed, self-resizing background image behind *parent*'s
        gridded/packed children so the image shows through the gutters."""
        lbl = tk.Label(parent, bd=0, highlightthickness=0, bg=self.C["bg_dark"])
        lbl.place(x=0, y=0, relwidth=1, relheight=1)
        lbl.lower()
        self._page_bg_labels[key] = lbl
        lbl.bind("<Configure>",
                 lambda e, k=key: self._render_page_bg(k, e.width, e.height))
        return lbl

    def _render_page_bg(self, key, w=None, h=None):
        lbl = self._page_bg_labels.get(key)
        if lbl is None:
            return
        if w is None:
            w = lbl.winfo_width()
        if h is None:
            h = lbl.winfo_height()
        photo = self._render_bg_image(w, h)
        if photo is None:
            lbl.configure(bg=self.C["bg_dark"])
            return
        lbl._img = photo        # keep ref on the widget
        lbl.configure(image=photo)

    def _refresh_backgrounds(self):
        """Re-render every background image for the current theme / size."""
        self._render_root_bg()
        for key in list(self._page_bg_labels.keys()):
            self._render_page_bg(key)

    # -------------------------------------------------- theming
    def _load_settings(self):
        try:
            with open(SETTINGS_PATH, "r") as fh:
                data = json.load(fh)
            if isinstance(data, dict):
                return data
        except Exception:
            pass
        return {}

    def _save_settings(self):
        try:
            with open(SETTINGS_PATH, "w") as fh:
                json.dump({"theme": self.theme}, fh)
        except Exception:
            pass

    def _recolor(self, widget, cmap):
        """Recursively remap themed colours on classic tk widgets."""
        opts = ("bg", "background", "fg", "foreground",
                "activebackground", "activeforeground",
                "highlightbackground", "insertbackground",
                "selectbackground", "selectforeground",
                "disabledforeground", "readonlybackground")
        for opt in opts:
            try:
                cur = str(widget.cget(opt))
            except Exception:
                continue
            if cur in cmap:
                try:
                    widget.configure(**{opt: cmap[cur]})
                except Exception:
                    pass
        for child in widget.winfo_children():
            self._recolor(child, cmap)

    def _apply_theme(self, name):
        if name not in THEMES:
            name = "dark"
        self.theme = name
        self.C = THEMES[name]
        # rebuild ttk styling for the new palette
        self._build_style()
        # remap classic tk widget colours
        if name == "light":
            cmap = dict(NEUTRAL_MAP)                       # dark -> light
        else:
            cmap = {v: k for k, v in NEUTRAL_MAP.items()}  # light -> dark
        self._recolor(self.root, cmap)
        # header stays accent blue in both themes
        self.root.configure(bg=self.C["bg_dark"])
        self._refresh_backgrounds()
        if getattr(self, "theme_var", None) is not None:
            try:
                self.theme_var.set(name)
            except Exception:
                pass
        self._save_settings()

    def _open_settings(self):
        # single instance
        if getattr(self, "_settings_win", None) is not None:
            try:
                if self._settings_win.winfo_exists():
                    self._settings_win.lift()
                    return
            except Exception:
                pass
        C = self.C
        win = tk.Toplevel(self.root)
        self._settings_win = win
        win.title("Settings")
        win.configure(bg=C["bg_panel"])
        win.resizable(False, False)
        win.transient(self.root)
        try:
            win.grab_set()
        except Exception:
            pass

        def _on_close():
            self._settings_win = None
            win.destroy()
        win.protocol("WM_DELETE_WINDOW", _on_close)

        pad = tk.Frame(win, bg=C["bg_panel"])
        pad.pack(fill="both", expand=True, padx=18, pady=16)

        tk.Label(pad, text="\u2699  Settings", bg=C["bg_panel"], fg=C["text"],
                 font=("Segoe UI", 14, "bold")).pack(anchor="w")

        tk.Label(pad, text="Appearance", bg=C["bg_panel"], fg=C["text_dim"],
                 font=("Segoe UI", 10, "bold")).pack(anchor="w", pady=(14, 4))

        self.theme_var = tk.StringVar(value=self.theme)
        row = tk.Frame(pad, bg=C["bg_panel"])
        row.pack(anchor="w", fill="x")
        ttk.Radiobutton(row, text="Light", value="light",
                        variable=self.theme_var,
                        command=lambda: self._apply_theme(
                            self.theme_var.get())).pack(side="left", padx=(0, 18))
        ttk.Radiobutton(row, text="Dark", value="dark",
                        variable=self.theme_var,
                        command=lambda: self._apply_theme(
                            self.theme_var.get())).pack(side="left")

        ttk.Separator(pad, orient="horizontal").pack(fill="x", pady=14)

        tk.Label(pad, text="Updates", bg=C["bg_panel"], fg=C["text_dim"],
                 font=("Segoe UI", 10, "bold")).pack(anchor="w", pady=(0, 4))
        upd = tk.Button(pad, text="Check for Updates", state="disabled",
                        relief="flat", bg=GREY_BTN, fg="#ffffff",
                        disabledforeground="#8a91a3",
                        font=("Segoe UI", 10), padx=10, pady=4)
        upd.pack(anchor="w")
        tk.Label(pad, text="(coming soon)", bg=C["bg_panel"], fg=C["text_dim"],
                 font=("Segoe UI", 8, "italic")).pack(anchor="w", pady=(2, 0))

        tk.Label(pad, text="Stork Solutions Ltd Aquatics Calibration Suite  \u2022  v1.1.1",
                 bg=C["bg_panel"], fg=C["text_dim"],
                 font=("Segoe UI", 8)).pack(anchor="w", pady=(16, 0))

        # position near the cog (top-right)
        win.update_idletasks()
        try:
            rx = self.root.winfo_rootx()
            rw = self.root.winfo_width()
            ry = self.root.winfo_rooty()
            ww = win.winfo_width()
            win.geometry("+%d+%d" % (rx + rw - ww - 20, ry + 66))
        except Exception:
            pass

    # -------------------------------------------------- header
    def _build_header(self):
        header = tk.Frame(self.root, bg=ACCENT, height=60)
        header.place(x=0, y=0, relwidth=1, height=60)

        # logo top-left
        if _PIL_OK and LOGO_B64 and not LOGO_B64.startswith("__"):
            try:
                raw = base64.b64decode(LOGO_B64)
                img = Image.open(io.BytesIO(raw)).convert("RGBA")
                h = 40
                w = int(img.width * (h / img.height))
                img = img.resize((w, h), Image.LANCZOS)
                self._logo_photo = ImageTk.PhotoImage(img)
                tk.Label(header, image=self._logo_photo, bg=ACCENT).place(
                    x=14, rely=0.5, anchor="w")
            except Exception:
                tk.Label(header, text="STORK", bg=ACCENT, fg=HIGHLIGHT,
                         font=("Segoe UI", 16, "bold")).place(
                             x=14, rely=0.5, anchor="w")

        tk.Label(header, text="Stork Solutions Ltd Aquatics Calibration Suite",
                 bg=ACCENT, fg="#ffffff",
                 font=("Segoe UI", 17, "bold")).place(relx=0.5, rely=0.5,
                                                      anchor="center")

        tk.Label(header, text="v1.1.1", bg=ACCENT, fg="#c7d0e0",
                 font=("Segoe UI", 11, "bold")).place(relx=1.0, rely=0.5,
                                                      anchor="e", x=-64)

        # settings cog (opens light/dark + updates popup)
        self.settings_btn = tk.Button(
            header, text="\u2699", command=self._open_settings,
            bg=ACCENT, fg="#ffffff", relief="flat", bd=0,
            activebackground="#14477e", activeforeground="#ffffff",
            font=("Segoe UI Symbol", 16), cursor="hand2")
        self.settings_btn.place(relx=1.0, rely=0.5, anchor="e", x=-14)

    # -------------------------------------------------- connection panel
    def _build_connection_panel(self):
        panel = tk.Frame(self.root, bg=BG_PANEL, height=52)
        panel.place(x=0, y=60, relwidth=1, height=52)

        # ---- Connection type selector (Serial vs WiFi TCP) ----
        tk.Label(panel, text="Connection:", bg=BG_PANEL, fg=TEXT,
                 font=("Segoe UI", 9, "bold")).pack(side="left", padx=(6, 2), pady=12)
        self.conn_type_var = tk.StringVar(value="Serial (USB / RTU)")
        self.conn_type_cb = ttk.Combobox(
            panel, textvariable=self.conn_type_var, width=16, state="readonly",
            values=["Serial (USB / RTU)", "WiFi TCP"])
        self.conn_type_cb.pack(side="left", pady=12)
        self.conn_type_cb.bind("<<ComboboxSelected>>", self._on_conn_type_change)

        # ---- Serial-specific widgets (COM port + baud) ----
        self.serial_frame = tk.Frame(panel, bg=BG_PANEL)
        self.serial_frame.pack(side="left")
        tk.Label(self.serial_frame, text="COM Port:", bg=BG_PANEL, fg=TEXT,
                 font=("Segoe UI", 9, "bold")).pack(side="left", padx=(10, 2), pady=12)
        self.port_var = tk.StringVar()
        self.port_cb = ttk.Combobox(self.serial_frame, textvariable=self.port_var,
                                    width=12, state="readonly")
        self.port_cb.pack(side="left", pady=12)
        self.btn_refresh = tk.Button(self.serial_frame, text="Refresh",
                                     command=self._refresh_ports,
                                     bg=GREY_BTN, fg=TEXT, relief="flat",
                                     activebackground=ACCENT, font=("Segoe UI", 8))
        self.btn_refresh.pack(side="left", padx=4, pady=12)
        tk.Label(self.serial_frame, text="Baud:", bg=BG_PANEL, fg=TEXT,
                 font=("Segoe UI", 9, "bold")).pack(side="left", padx=(10, 2), pady=12)
        self.baud_var = tk.StringVar(value="9600")
        self.baud_cb = ttk.Combobox(self.serial_frame, textvariable=self.baud_var,
                                    width=7, state="readonly",
                                    values=["4800", "9600", "19200"])
        self.baud_cb.pack(side="left", pady=12)

        # ---- TCP-specific widgets (host + port + framer) ----
        self.tcp_frame = tk.Frame(panel, bg=BG_PANEL)
        # not packed initially -- shown when "WiFi TCP" selected
        tk.Label(self.tcp_frame, text="Host IP:", bg=BG_PANEL, fg=TEXT,
                 font=("Segoe UI", 9, "bold")).pack(side="left", padx=(10, 2), pady=12)
        self.host_var = tk.StringVar(value="192.168.1.100")
        self.host_entry = tk.Entry(self.tcp_frame, textvariable=self.host_var, width=15,
                                   bg="#0e1526", fg=TEXT, insertbackground=TEXT,
                                   relief="flat")
        self.host_entry.pack(side="left", pady=12)
        tk.Label(self.tcp_frame, text="Port:", bg=BG_PANEL, fg=TEXT,
                 font=("Segoe UI", 9, "bold")).pack(side="left", padx=(10, 2), pady=12)
        self.tcp_port_var = tk.StringVar(value="8888")
        self.tcp_port_entry = tk.Entry(self.tcp_frame, textvariable=self.tcp_port_var,
                                       width=6, bg="#0e1526", fg=TEXT,
                                       insertbackground=TEXT, relief="flat")
        self.tcp_port_entry.pack(side="left", pady=12)
        # framer_var retained (no widget) — referenced by TCP code paths
        self.framer_var = tk.StringVar(value="Modbus/TCP")
        tk.Label(self.tcp_frame,
                 text="Reads via ASCII · Calibration = Serial only",
                 bg=BG_PANEL, fg=TEXT_DIM,
                 font=("Segoe UI", 8, "italic")).pack(side="left", padx=(12, 2), pady=12)

        # ---- Shared widgets (address + scan + connect + LED) ----
        tk.Label(panel, text="Address:", bg=BG_PANEL, fg=TEXT,
                 font=("Segoe UI", 9, "bold")).pack(side="left", padx=(10, 2), pady=12)
        self.addr_var = tk.IntVar(value=2)
        self.addr_sb = ttk.Spinbox(panel, from_=1, to=247, textvariable=self.addr_var,
                                   width=5)
        self.addr_sb.pack(side="left", pady=12)

        self.btn_scan = tk.Button(panel, text="Scan Addresses",
                                  command=self._scan_addresses,
                                  bg=AMBER, fg="#101010", relief="flat",
                                  activebackground="#e0a800",
                                  font=("Segoe UI", 8, "bold"))
        self.btn_scan.pack(side="left", padx=10, pady=12)

        self.btn_connect = tk.Button(panel, text="Connect", command=self._toggle_connect,
                                     bg=GREEN, fg="#0b1a0b", relief="flat",
                                     activebackground="#27ae60", width=11,
                                     font=("Segoe UI", 9, "bold"))
        self.btn_connect.pack(side="left", padx=8, pady=12)

        # LED indicator
        self.led = tk.Canvas(panel, width=20, height=20, bg=BG_PANEL,
                             highlightthickness=0)
        self.led.pack(side="left", padx=(4, 6), pady=12)
        self._led_item = self.led.create_oval(3, 3, 17, 17, fill=RED, outline="#000")

        tk.Label(panel, text="", bg=BG_PANEL).pack(side="left")

    def _on_conn_type_change(self, event=None):
        """Swap serial/TCP widgets when the connection type dropdown changes."""
        if self.link.connected:
            # Don't allow switching while connected
            messagebox.showinfo("Connection",
                                "Disconnect before changing connection type.")
            # revert selection to match current link mode
            self.conn_type_var.set("WiFi TCP" if self.link.mode == "tcp"
                                   else "Serial (USB / RTU)")
            return
        if self.conn_type_var.get() == "WiFi TCP":
            self.serial_frame.pack_forget()
            self.tcp_frame.pack(side="left", after=self.conn_type_cb)
        else:
            self.tcp_frame.pack_forget()
            self.serial_frame.pack(side="left", after=self.conn_type_cb)

