    def _build_tabs(self):
        container = tk.Frame(self.root, bg=BG_DARK)
        container.place(x=0, y=112, relwidth=1, relheight=1, height=-112)
        self._install_page_bg(container, "container")

        self.nb = ttk.Notebook(container)
