        self.ph_tab = tk.Frame(self.nb, bg=BG_DARK)
        self.tds_tab = tk.Frame(self.nb, bg=BG_DARK)
        self.nb.add(self.ph_tab, text="  pH Calibration  ")
        self.nb.add(self.tds_tab, text="  TDS Calibration  ")

        self._build_ph_tab()
        self._build_tds_tab()

